import React from 'react'
import './Navbar.css'

function Nav() {
  return (
    <div className='navbar'>
        <h1>Expense Tracker App <i class="fa-solid fa-wallet"></i></h1>
        <h4>--A simple solution to track your expenses--</h4>
    </div>
  )
}

export default Nav;
